import { useState } from "react";
import Auth from "./Auth";
import BMI from "./BMI";
import "./App.css";

function App() {
  const [token, setToken] = useState(localStorage.getItem("token") || null);

  const handleLogout = () => {
    localStorage.removeItem("token");
    setToken(null);
  };

  return (
    <div className="app">
      {token ? (
        <BMI token={token} onLogout={handleLogout} />
      ) : (
        <Auth onLogin={setToken} />
      )}
    </div>
  );
}

export default App;
